#include <bits/stdc++.h>
using namespace std;

int n,m;
long long res=0;

long long qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base;
        base=base*base,b>>=1;
    }
    return ans;
}

int mu(int x){
    int res=1;
    for(int i=2;i*i<=x && res;i++)
        if(x%i==0){
            int cnt=0;
            while(x%i==0) cnt++,x/=i;
            if(cnt>1) res=0;
            else res=-res;
        }
    if(x>1)
        res=-res;
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i*i<=m;i++)
        if(m%i==0){
            res+=mu(i)*qpow(m/i,n);
            if(i*i!=m)
                res+=mu(m/i)*qpow(i,n);
        }
    printf("%lld",res);
    return 0;
}
